--
-- Table structure for table `assessment_version_rule`
--

DROP TABLE IF EXISTS `assessment_version_rule`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `assessment_version_rule` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `version_id` bigint NOT NULL COMMENT '版本ID',
  `min_score` int NOT NULL COMMENT '最小分',
  `max_score` int NOT NULL COMMENT '最大分',
  `result_level` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '结果等级',
  `result_summary` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '结果说明',
  `suggestion` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '建议',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_version_rule_version_id` (`version_id`),
  CONSTRAINT `fk_version_rule_version` FOREIGN KEY (`version_id`) REFERENCES `assessment_scale_version` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=82 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='量表版本判定规则表';
/*!40101 SET character_set_client = @saved_cs_client */;

