--
-- Table structure for table `student_assessment_semester_summary`
--

DROP TABLE IF EXISTS `student_assessment_semester_summary`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_assessment_semester_summary` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `student_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '学生学号',
  `semester` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '学期',
  `tested_count` int NOT NULL DEFAULT '0' COMMENT '已测数量',
  `score_summary` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '分数汇总，如 PHQ9:10, GAD7:8, WHO5:16',
  `semester_level` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '学期总等级：危险/轻危/无',
  `last_tested_at` datetime DEFAULT NULL COMMENT '最后测试时间',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_student_semester` (`student_id`,`semester`),
  KEY `idx_student_id` (`student_id`),
  KEY `idx_semester` (`semester`)
) ENGINE=InnoDB AUTO_INCREMENT=483 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='学生学期测评汇总表';
/*!40101 SET character_set_client = @saved_cs_client */;

